(97, 4, 'Samsung Galaxy A17 5G 8GB 128GB', 'samsung-galaxy-a17-5g-8gb-128gb', 'Samsung', NULL, 6390000, 6090000, 20, '<div id="cpsContentSEO"><blockquote>
